use strict;
use warnings;
use PDF::API2;
use Text::PDF::Text;

# Function to extract date and author from the PDF
sub extract_info {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);
    my $text = Text::PDF::Text->new($pdf);

    my $info = {};
    while (my $line = $text->get_textline) {
        if ($line =~ /Created:\s*(\d{1,2}\/\d{1,2}\/\d{2,4})/) {
            $info->{created} = $1;
        }
        if ($line =~ /Author:\s*(\w+)/) {
            $info->{author} = $1;
        }
    }

    return $info;
}

# Function to extract tables from the PDF
sub extract_tables {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);
    my $text = Text::PDF::Text->new($pdf);

    my @tables = [];

    while (my $line = $text->get_textline) {
        if ($line =~ /^\s*\d+\s+/ && $line =~ /\d+/) {
            push @tables, $line;
        }
    }

    return \@tables;
}

